  1	// Shared URL-state helper for list views (artifacts, etc.).
  2	// Reads/writes the well-known query params (q, mediaType, groupBy, sort,
  3	// staleness, phase, prefix, filters.*) while preserving any unrelated keys,
  4	// including ?back=.
  5	
  6	export type GroupBy = 'folder' | 'prefix' | 'mediaType' | 'workflowStage';
  7	
  8	// Reserved facet URL keys (TD-029 facet contract):
  9	//   q          — full-text search query (single)
 10	//   mediaType  — media-type filter (single, supports X/* wildcard)
 11	//   staleness  — staleness filter (single)
 12	//   phase      — HELIX phase filter (single)
 13	//   prefix     — id-prefix filter (multi: comma-separated)
 14	//   sort       — sort key (single)
 15	// groupBy is a Story-5 categorization axis (not a filter) and travels in
 16	// the same URL but does NOT narrow results.
 17	const KNOWN_KEYS = new Set(['q', 'mediaType', 'groupBy', 'sort', 'staleness', 'phase', 'prefix']);
 18	const FILTER_PREFIX = 'filter.';
 19	
 20	export interface ListURLState {
 21		q: string;
 22		mediaType: string | null;
 23		groupBy: GroupBy;
 24		sort: string | null;
 25		staleness: string | null;
 26		phase: string | null;
 27		prefix: string[];
 28		filters: Record<string, string>;
 29	}
 30	
 31	export const DEFAULT_GROUP_BY: GroupBy = 'folder';
 32	
 33	function parseGroupBy(raw: string | null): GroupBy {
 34		if (raw === 'prefix' || raw === 'mediaType' || raw === 'folder' || raw === 'workflowStage')
 35			return raw;
 36		return DEFAULT_GROUP_BY;
 37	}
 38	
 39	export function readState(params: URLSearchParams): ListURLState {
 40		const filters: Record<string, string> = {};
 41		for (const [k, v] of params.entries()) {
 42			if (k.startsWith(FILTER_PREFIX)) filters[k.slice(FILTER_PREFIX.length)] = v;
 43		}
 44		const rawPrefix = params.get('prefix');
 45		const prefix = rawPrefix
 46			? rawPrefix
 47					.split(',')
 48					.map((s) => s.trim())
 49					.filter((s) => s.length > 0)
 50			: [];
 51		return {
 52			q: params.get('q') ?? '',
 53			mediaType: params.get('mediaType'),
 54			groupBy: parseGroupBy(params.get('groupBy')),
 55			sort: params.get('sort'),
 56			staleness: params.get('staleness'),
 57			phase: params.get('phase'),
 58			prefix,
 59			filters
 60		};
 61	}
 62	
 63	// writeState mutates a copy of `params` with the patch applied. Unrelated
 64	// keys (including `back`) are preserved. Empty/null values delete the key.
 65	export function writeState(params: URLSearchParams, patch: Partial<ListURLState>): URLSearchParams {
 66		const next = new URLSearchParams(params);
 67	
 68		if ('q' in patch) {
 69			if (patch.q) next.set('q', patch.q);
 70			else next.delete('q');
 71		}
 72		if ('mediaType' in patch) {
 73			if (patch.mediaType) next.set('mediaType', patch.mediaType);
 74			else next.delete('mediaType');
 75		}
 76		if ('groupBy' in patch) {
 77			if (patch.groupBy && patch.groupBy !== DEFAULT_GROUP_BY) next.set('groupBy', patch.groupBy);
 78			else next.delete('groupBy');
 79		}
 80		if ('sort' in patch) {
 81			if (patch.sort) next.set('sort', patch.sort);
 82			else next.delete('sort');
 83		}
 84		if ('staleness' in patch) {
 85			if (patch.staleness) next.set('staleness', patch.staleness);
 86			else next.delete('staleness');
 87		}
 88		if ('phase' in patch) {
 89			if (patch.phase) next.set('phase', patch.phase);
 90			else next.delete('phase');
 91		}
 92		if ('prefix' in patch) {
 93			const arr = patch.prefix ?? [];
 94			if (arr.length > 0) next.set('prefix', arr.join(','));
 95			else next.delete('prefix');
 96		}
 97		if ('filters' in patch && patch.filters) {
 98			// Replace only the filter.* keys; leave everything else intact.
 99			for (const k of Array.from(next.keys())) {
100				if (k.startsWith(FILTER_PREFIX)) next.delete(k);
101			}
102			for (const [k, v] of Object.entries(patch.filters)) {
103				if (v) next.set(FILTER_PREFIX + k, v);
104			}
105		}
106	
107		return next;
108	}
